sql:
SELECT correlation_value, location_id, sample_date, confidence_interval
FROM correlation_matrix
WHERE location_id = 1 AND param1 = 'pH' AND param2 = 'EC';

external_knowledge:
- 'hidden treasures' refers to the soil samples; 
- 'deeper than the first' means sample_id > 1; 
- 'the realm of clay' refers to the soil type 'clay';
- 'where do they lie buried' refers to the location where the samples were collected;
- 'identifiers of these treasures' refers to the sample_id;
- 'type' refers to the soil_type;
- 'name of their resting place' refers to the location_name;
- 'secrets of these sites' refers to the location_id;
- 'from the deepest to the shallower' means sorting the results by location_id in descending order;
- 'top ten findings' refers to LIMIT 10.

- 'garden of the Earth' refers to the geographical locations;
- 'soil whispers tales of clay' means soil texture is 'Clayey';
- 'elevation tales dance between the shadows of sea level and the embrace of mountains' means elevation is between 0 and 2000 meters;
- 'soil's acidic embrace' refers to the pH value of the soil;
- 'electrical spark' refers to the electrical conductivity (EC) of the soil;
- 'softer than a whisper' means pH value is less than 7.0;
- 'softer than a candle's flame' means EC value is less than 0.5.

sql:
SELECT sample_id
FROM soil_parameters
WHERE pH > 7;

SELECT COUNT(DISTINCT user_id) AS unique_users
FROM (
  SELECT user_id FROM access_logs
  UNION
  SELECT collector_id AS user_id FROM soil_samples
) AS combined_users;

SELECT param1, param2, correlation_value
FROM correlation_matrix
WHERE location_id = 0;

SELECT sample_id, sampling_depth
FROM soil_samples
WHERE sampling_depth = (SELECT MAX(sampling_depth) FROM soil_samples);

SELECT locations.location_name, soil_samples.soil_type
FROM locations
INNER JOIN soil_samples ON locations.location_id = soil_samples.location_id;
